#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code for RQ 6.9.8)
# =============================================================================
"""
Step ID: step01
Step Name: Reshape Data from Wide to Long Format
RQ: results/ch6/6.9.8
Generated: 2026-01-20

PURPOSE:
Reshape accuracy and confidence theta scores from wide format (400 rows x 3 schema conditions)
to long format (1200 rows x 5 columns) for correlation analysis.

EXPECTED INPUTS:
- results/ch5/5.4.1/data/step03_theta_scores.csv (400 rows, wide format)
  Columns: composite_ID, theta_common, theta_congruent, theta_incongruent
- results/ch6/6.5.1/data/step03_theta_confidence.csv (400 rows, wide format)
  Columns: composite_ID, theta_Common, theta_Congruent, theta_Incongruent

EXPECTED OUTPUTS:
- results/ch6/6.9.8/data/step01_reshaped_long.csv (1200 rows x 5 columns)
  Columns: UID, test, schema_condition, theta_accuracy, theta_confidence

VALIDATION CRITERIA:
- Exactly 1200 rows (100 UIDs x 4 tests x 3 schema conditions)
- No missing values
- Theta values in [-3, 3]
- Balanced design: each UID has 12 rows

g_code REASONING:
- Approach: Use pandas.melt() for wide-to-long transformation, then merge
- Why this approach: Standard pandas reshape operation, efficient and readable
- Data flow: Load wide files -> melt each -> merge on composite_ID + schema_condition
- Expected performance: <5 seconds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.8
PROJECT_ROOT = RQ_DIR.parents[2]  # /home/etai/projects/REMEMVR

LOG_FILE = RQ_DIR / "logs" / "step01_reshape_data.log"
OUTPUT_FILE = RQ_DIR / "data" / "step01_reshaped_long.csv"

# Input files
CH5_DATA = PROJECT_ROOT / "results" / "ch5" / "5.4.1" / "data" / "step03_theta_scores.csv"
CH6_DATA = PROJECT_ROOT / "results" / "ch6" / "6.5.1" / "data" / "step03_theta_confidence.csv"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console with flush."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 01: Reshape Data from Wide to Long Format")

        # =====================================================================
        # STEP 1: Load and Reshape Accuracy Data
        # =====================================================================
        log("[LOAD] Loading accuracy data...")
        df_acc = pd.read_csv(CH5_DATA)
        log(f"[LOADED] Accuracy: {len(df_acc)} rows, {len(df_acc.columns)} columns")
        log(f"[INFO] Columns: {', '.join(df_acc.columns.tolist())}")

        # Parse composite_ID to extract UID and test
        # Ch5 accuracy format: A010_1, A010_2, etc. (need to convert 1-4 to T1-T4)
        log("[PARSE] Extracting UID and test from composite_ID...")
        df_acc['UID'] = df_acc['composite_ID'].str.extract(r'([A-Z]\d+)')[0]
        df_acc['test_raw'] = df_acc['composite_ID'].str.extract(r'_(\d)$')[0]
        df_acc['test'] = 'T' + df_acc['test_raw']

        # Standardize composite_ID to match Ch6 format (A010_T1 instead of A010_1)
        df_acc['composite_ID'] = df_acc['UID'] + '_' + df_acc['test']

        log(f"[INFO] Unique UIDs: {df_acc['UID'].nunique()}, Tests: {sorted(df_acc['test'].unique().tolist())}")

        # Reshape accuracy wide to long
        log("[RESHAPE] Melting accuracy data to long format...")
        df_acc_long = pd.melt(
            df_acc,
            id_vars=['composite_ID', 'UID', 'test'],
            value_vars=['theta_common', 'theta_congruent', 'theta_incongruent'],
            var_name='schema_condition_raw',
            value_name='theta_accuracy'
        )

        # Clean labels: 'theta_common' -> 'Common'
        df_acc_long['schema_condition'] = df_acc_long['schema_condition_raw'].str.replace('theta_', '').str.title()
        df_acc_long = df_acc_long.drop(columns=['schema_condition_raw'])

        log(f"[RESHAPED] Accuracy reshaped: {len(df_acc_long)} rows")
        log(f"[INFO] Schema conditions: {df_acc_long['schema_condition'].unique().tolist()}")

        # =====================================================================
        # STEP 2: Load and Reshape Confidence Data
        # =====================================================================
        log("[LOAD] Loading confidence data...")
        df_conf = pd.read_csv(CH6_DATA)
        log(f"[LOADED] Confidence: {len(df_conf)} rows, {len(df_conf.columns)} columns")
        log(f"[INFO] Columns: {', '.join(df_conf.columns.tolist())}")

        # Parse composite_ID to extract UID and test
        # Ch6 confidence format: A010_T1, A010_T2, etc.
        log("[PARSE] Extracting UID and test from composite_ID...")
        df_conf['UID'] = df_conf['composite_ID'].str.extract(r'([A-Z]\d+)')[0]
        df_conf['test'] = df_conf['composite_ID'].str.extract(r'_(T\d)$')[0]

        # Reshape confidence wide to long
        log("[RESHAPE] Melting confidence data to long format...")
        df_conf_long = pd.melt(
            df_conf,
            id_vars=['composite_ID', 'UID', 'test'],
            value_vars=['theta_Common', 'theta_Congruent', 'theta_Incongruent'],
            var_name='schema_condition_raw',
            value_name='theta_confidence'
        )

        # Clean labels: 'theta_Common' -> 'Common'
        df_conf_long['schema_condition'] = df_conf_long['schema_condition_raw'].str.replace('theta_', '')
        df_conf_long = df_conf_long.drop(columns=['schema_condition_raw'])

        log(f"[RESHAPED] Confidence reshaped: {len(df_conf_long)} rows")

        # =====================================================================
        # STEP 3: Merge Accuracy and Confidence
        # =====================================================================
        log("[MERGE] Joining accuracy and confidence datasets...")
        df_merged = pd.merge(
            df_acc_long[['composite_ID', 'UID', 'test', 'schema_condition', 'theta_accuracy']],
            df_conf_long[['composite_ID', 'schema_condition', 'theta_confidence']],
            on=['composite_ID', 'schema_condition'],
            how='inner'
        )

        log(f"[MERGED] Result: {len(df_merged)} rows, {len(df_merged.columns)} columns")

        # Drop composite_ID (not needed in final output)
        df_merged = df_merged[['UID', 'test', 'schema_condition', 'theta_accuracy', 'theta_confidence']]

        # =====================================================================
        # STEP 4: Validate Output
        # =====================================================================
        log("[VALIDATION] Checking data quality...")

        errors = []

        # Check row count
        if len(df_merged) != 1200:
            errors.append(f"Expected 1200 rows, got {len(df_merged)}")
        else:
            log("[PASS] Row count: 1200")

        # Check columns
        expected_cols = ['UID', 'test', 'schema_condition', 'theta_accuracy', 'theta_confidence']
        if df_merged.columns.tolist() != expected_cols:
            errors.append(f"Column mismatch. Expected {expected_cols}, got {df_merged.columns.tolist()}")
        else:
            log("[PASS] Columns: UID, test, schema_condition, theta_accuracy, theta_confidence")

        # Check for missing values
        missing_count = df_merged[['theta_accuracy', 'theta_confidence']].isnull().sum().sum()
        if missing_count > 0:
            errors.append(f"Found {missing_count} missing values in theta columns")
        else:
            log("[PASS] No missing values")

        # Check theta value ranges
        theta_acc_min, theta_acc_max = df_merged['theta_accuracy'].min(), df_merged['theta_accuracy'].max()
        theta_conf_min, theta_conf_max = df_merged['theta_confidence'].min(), df_merged['theta_confidence'].max()

        log(f"[INFO] Accuracy range: [{theta_acc_min:.3f}, {theta_acc_max:.3f}]")
        log(f"[INFO] Confidence range: [{theta_conf_min:.3f}, {theta_conf_max:.3f}]")

        if theta_acc_min < -3 or theta_acc_max > 3:
            errors.append(f"Accuracy theta out of range [-3, 3]: [{theta_acc_min}, {theta_acc_max}]")
        else:
            log("[PASS] Accuracy theta in range [-3, 3]")

        if theta_conf_min < -3 or theta_conf_max > 3:
            errors.append(f"Confidence theta out of range [-3, 3]: [{theta_conf_min}, {theta_conf_max}]")
        else:
            log("[PASS] Confidence theta in range [-3, 3]")

        # Check schema conditions
        schema_values = set(df_merged['schema_condition'].unique())
        expected_schemas = {'Common', 'Congruent', 'Incongruent'}
        if schema_values != expected_schemas:
            errors.append(f"Schema condition mismatch. Expected {expected_schemas}, got {schema_values}")
        else:
            log("[PASS] Schema conditions: Common, Congruent, Incongruent")

        # Check test values
        test_values = set(df_merged['test'].unique())
        expected_tests = {'T1', 'T2', 'T3', 'T4'}
        if test_values != expected_tests:
            errors.append(f"Test value mismatch. Expected {expected_tests}, got {test_values}")
        else:
            log("[PASS] Test values: T1, T2, T3, T4")

        # Check unique UIDs
        n_uids = df_merged['UID'].nunique()
        if n_uids != 100:
            errors.append(f"Expected 100 unique UIDs, got {n_uids}")
        else:
            log("[PASS] 100 unique UIDs")

        # Check balanced design
        uid_counts = df_merged.groupby('UID').size()
        if not (uid_counts == 12).all():
            errors.append(f"Design imbalance: some UIDs don't have 12 rows. Range: [{uid_counts.min()}, {uid_counts.max()}]")
        else:
            log("[PASS] Balanced design: each UID has 12 rows (4 tests x 3 conditions)")

        # =====================================================================
        # STEP 5: Save Output
        # =====================================================================
        if errors:
            log("[VALIDATION] FAIL - Errors detected:")
            for error in errors:
                log(f"  - {error}")
            raise ValueError(f"Validation failed with {len(errors)} error(s)")

        log("[VALIDATION] PASS - All checks passed")

        df_merged.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] Output: {OUTPUT_FILE}")

        log("[SUCCESS] Step 01 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
